#!/usr/bin/env python3
from __future__ import annotations

import argparse
import csv
import json
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Any


DEFAULT_ROOTS = [
    Path.home() / "Library" / "Containers" / "cn.com.10jqka.macstockPro" / "Data",
    Path.home() / "Library" / "Containers" / "cn.com.10jqka.ixcs" / "Data",
    Path.home() / "Library" / "Group Containers" / "group.cn.com.10jqka.ixcs",
]


@dataclass
class Holding:
    symbol: str
    name: str
    quantity: int
    cost_price: float | None
    asset_type: str
    source_path: str
    ledger_ids: list[str]


def normalize_code(value: Any) -> str:
    raw = str(value or "").strip().upper()
    if not raw or raw == "NAN":
        return ""
    if raw.endswith(".XSHG"):
        return raw.replace(".XSHG", ".SH")
    if raw.endswith(".XSHE"):
        return raw.replace(".XSHE", ".SZ")
    if raw.endswith((".SH", ".SZ", ".HK")):
        return raw
    if raw.startswith("SH") and len(raw) >= 8:
        return f"{raw[2:8]}.SH"
    if raw.startswith("SZ") and len(raw) >= 8:
        return f"{raw[2:8]}.SZ"
    if raw.isdigit() and len(raw) == 6:
        market = "SH" if raw.startswith(("5", "6", "9")) else "SZ"
        return f"{raw}.{market}"
    if raw.isdigit() and len(raw) == 5:
        return f"{raw}.HK"
    return raw


def infer_asset_type(symbol: str) -> str:
    code = symbol.split(".")[0]
    if code.startswith(("5", "1", "15")):
        return "fund"
    return "stock"


def normalize_side(value: Any) -> str:
    text = str(value or "").strip().upper()
    if any(k in text for k in ["买", "BUY", "B", "证券买入", "申购"]):
        return "BUY"
    if any(k in text for k in ["卖", "SELL", "S", "证券卖出", "赎回"]):
        return "SELL"
    return text


def discover_roots(extra_roots: list[str] | None = None) -> list[Path]:
    roots = list(DEFAULT_ROOTS)
    containers_root = Path.home() / "Library" / "Containers"
    if containers_root.exists():
        for d in containers_root.iterdir():
            if not d.is_dir():
                continue
            candidate = d / "Data" / "Documents" / "cn.com.10jqka.ixcs"
            if candidate.exists():
                roots.append(d / "Data")
    if extra_roots:
        roots.extend(Path(x).expanduser().resolve() for x in extra_roots)

    uniq: list[Path] = []
    seen: set[Path] = set()
    for p in roots:
        p = p.resolve()
        if p in seen:
            continue
        seen.add(p)
        uniq.append(p)
    return uniq


def list_ledger_files(roots: list[Path]) -> list[Path]:
    files: list[Path] = []
    for root in roots:
        if not root.exists():
            continue
        try:
            files.extend(root.rglob("XcsLscjDataFile_*"))
        except Exception:
            continue
    uniq = sorted({p.resolve() for p in files if p.is_file()})
    return uniq


def extract_ledger_ids(path: Path) -> list[str]:
    name = path.name
    parts = name.split("_")
    ids = [p for p in parts[1:] if p.isdigit()]
    return ids


def parse_ledger(path: Path) -> list[Holding]:
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return []
    if not isinstance(payload, dict):
        return []

    state: dict[str, dict[str, Any]] = {}
    for code_key, by_date in payload.items():
        if code_key in {"startdate", "enddate", ""}:
            continue
        if not isinstance(by_date, dict):
            continue
        for _day, records in by_date.items():
            if not isinstance(records, list):
                continue
            for item in records:
                if not isinstance(item, dict):
                    continue
                symbol = normalize_code(item.get("zqdm", code_key))
                if not symbol:
                    continue
                side = normalize_side(item.get("czmc", ""))
                if side not in {"BUY", "SELL"}:
                    continue
                try:
                    qty = int(float(item.get("cjsl", 0) or 0))
                except Exception:
                    qty = 0
                try:
                    price = float(item.get("cjjg", 0) or 0)
                except Exception:
                    price = 0.0
                if qty <= 0:
                    continue
                if price <= 0:
                    continue

                slot = state.setdefault(
                    symbol,
                    {
                        "qty": 0.0,
                        "cost_total": 0.0,
                        "name": str(item.get("zqmc", "") or "").strip(),
                    },
                )
                if not slot.get("name"):
                    slot["name"] = str(item.get("zqmc", "") or "").strip()

                if side == "BUY":
                    slot["qty"] += qty
                    if price > 0:
                        slot["cost_total"] += price * qty
                elif side == "SELL":
                    if slot["qty"] <= 0:
                        continue
                    sell_qty = min(slot["qty"], qty)
                    avg_cost = slot["cost_total"] / slot["qty"] if slot["qty"] > 0 else 0.0
                    slot["qty"] -= sell_qty
                    slot["cost_total"] -= avg_cost * sell_qty
                    if slot["qty"] < 1e-6:
                        slot["qty"] = 0.0
                        slot["cost_total"] = 0.0

    holdings: list[Holding] = []
    ledger_ids = extract_ledger_ids(path)
    for symbol, slot in sorted(state.items()):
        qty = int(round(float(slot.get("qty", 0.0))))
        if qty <= 0:
            continue
        cost_total = float(slot.get("cost_total", 0.0))
        avg_cost = cost_total / qty if qty > 0 and cost_total > 0 else None
        holdings.append(
            Holding(
                symbol=symbol,
                name=str(slot.get("name", "") or "").strip(),
                quantity=qty,
                cost_price=avg_cost,
                asset_type=infer_asset_type(symbol),
                source_path=str(path),
                ledger_ids=ledger_ids,
            )
        )
    return holdings


def load_selection_config(path: str | None) -> dict[str, Any]:
    if not path:
        return {}
    fp = Path(path).expanduser().resolve()
    if not fp.exists():
        return {}
    try:
        payload = json.loads(fp.read_text(encoding="utf-8"))
        return payload if isinstance(payload, dict) else {}
    except Exception:
        return {}


def summarize_holdings(holdings: list[Holding]) -> dict[str, Any]:
    stocks = [h for h in holdings if h.asset_type == "stock" and not h.symbol.endswith(".HK")]
    hk = [h for h in holdings if h.asset_type == "stock" and h.symbol.endswith(".HK")]
    funds = [h for h in holdings if h.asset_type == "fund"]
    return {
        "total": len(holdings),
        "a_stock": len(stocks),
        "hk_stock": len(hk),
        "fund": len(funds),
        "symbols": [h.symbol for h in holdings],
    }


def write_csv(path: Path, holdings: list[Holding]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("w", encoding="utf-8-sig", newline="") as f:
        writer = csv.DictWriter(
            f,
            fieldnames=["symbol", "asset_type", "name", "quantity", "cost_price", "source_path", "ledger_ids"],
        )
        writer.writeheader()
        for h in holdings:
            writer.writerow(
                {
                    "symbol": h.symbol,
                    "asset_type": h.asset_type,
                    "name": h.name,
                    "quantity": h.quantity,
                    "cost_price": "" if h.cost_price is None else f"{h.cost_price:.6f}",
                    "source_path": h.source_path,
                    "ledger_ids": "|".join(h.ledger_ids),
                }
            )


def cmd_list(args: argparse.Namespace) -> int:
    roots = discover_roots(args.scan_root)
    files = list_ledger_files(roots)
    if not files:
        print("未找到同花顺账本文件", file=sys.stderr)
        return 1

    payload = []
    for fp in files:
        holdings = parse_ledger(fp)
        payload.append(
            {
                "path": str(fp),
                "ledger_ids": extract_ledger_ids(fp),
                "summary": summarize_holdings(holdings),
            }
        )

    print(json.dumps(payload, ensure_ascii=False, indent=2))
    return 0


def cmd_export(args: argparse.Namespace) -> int:
    roots = discover_roots(args.scan_root)
    files = list_ledger_files(roots)
    if not files:
        print("未找到同花顺账本文件", file=sys.stderr)
        return 1

    cfg = load_selection_config(args.selection_config)
    selected_ids = {str(x).strip() for x in (args.ledger_id or cfg.get("selected_ledger_ids", [])) if str(x).strip()}
    allowlist = {normalize_code(x) for x in (cfg.get("symbol_allowlist", []) or []) if normalize_code(x)}
    denylist = {normalize_code(x) for x in (cfg.get("symbol_denylist", []) or []) if normalize_code(x)}
    stock_only = bool(args.stock_only or cfg.get("stock_only", False))

    selected: list[Path] = []
    for fp in files:
        ids = set(extract_ledger_ids(fp))
        if selected_ids:
            if ids & selected_ids:
                selected.append(fp)
        elif allowlist:
            selected.append(fp)
        elif len(files) == 1:
            selected.append(fp)

    if not selected:
        print(
            "存在多个账本，但既没有 selected_ledger_ids，也没有 symbol_allowlist；先运行 list 查看候选账本。",
            file=sys.stderr,
        )
        return 2

    merged: list[Holding] = []
    for fp in selected:
        merged.extend(parse_ledger(fp))

    if allowlist:
        merged = [h for h in merged if h.symbol in allowlist]
    if denylist:
        merged = [h for h in merged if h.symbol not in denylist]
    if stock_only:
        merged = [h for h in merged if h.asset_type == "stock"]

    summary = summarize_holdings(merged)
    out_dir = Path(args.out_dir).expanduser().resolve()
    out_dir.mkdir(parents=True, exist_ok=True)
    csv_path = out_dir / args.csv_name
    json_path = out_dir / args.json_name

    write_csv(csv_path, merged)
    json_path.write_text(
        json.dumps(
            {
                "selected_ledger_ids": sorted(selected_ids),
                "symbol_allowlist": sorted(allowlist),
                "symbol_denylist": sorted(denylist),
                "selected_files": [str(x) for x in selected],
                "summary": summary,
                "holdings": [
                    {
                        "symbol": h.symbol,
                        "asset_type": h.asset_type,
                        "name": h.name,
                        "quantity": h.quantity,
                        "cost_price": h.cost_price,
                        "source_path": h.source_path,
                        "ledger_ids": h.ledger_ids,
                    }
                    for h in merged
                ],
            },
            ensure_ascii=False,
            indent=2,
        ),
        encoding="utf-8",
    )

    print(
        json.dumps(
            {
                "csv": str(csv_path),
                "json": str(json_path),
                "summary": summary,
                "selected_files": [str(x) for x in selected],
            },
            ensure_ascii=False,
            indent=2,
        )
    )
    return 0


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="从同花顺本地账本提取分账本持仓")
    sub = parser.add_subparsers(dest="command", required=True)

    p_list = sub.add_parser("list", help="列出本机同花顺账本及各账本持仓摘要")
    p_list.add_argument("--scan-root", action="append", default=[], help="附加扫描目录")
    p_list.set_defaults(func=cmd_list)

    p_export = sub.add_parser("export", help="按显式 ledger id 导出持仓")
    p_export.add_argument("--scan-root", action="append", default=[], help="附加扫描目录")
    p_export.add_argument("--ledger-id", action="append", default=[], help="指定要导出的 ledger id，可重复")
    p_export.add_argument("--stock-only", action="store_true", help="只导出股票，排除基金")
    p_export.add_argument("--selection-config", default="", help="JSON 选择配置文件，支持 selected_ledger_ids / symbol_allowlist / symbol_denylist / stock_only")
    p_export.add_argument("--out-dir", default=".", help="输出目录")
    p_export.add_argument("--csv-name", default="ths_selected_holdings.csv", help="输出 CSV 文件名")
    p_export.add_argument("--json-name", default="ths_selected_holdings.json", help="输出 JSON 文件名")
    p_export.set_defaults(func=cmd_export)

    return parser


def main() -> int:
    parser = build_parser()
    args = parser.parse_args()
    return int(args.func(args))


if __name__ == "__main__":
    raise SystemExit(main())

