from pathlib import Path
import sqlite3, shutil, tempfile, os
bases = [
    Path.home()/ 'Library/Application Support/Google/Chrome',
    Path.home()/ 'Library/Application Support/Chromium',
    Path.home()/ 'Library/Application Support/Microsoft Edge',
]
for base in bases:
    print('\nBASE', base)
    if not base.exists():
        continue
    profiles=[]
    for p in base.iterdir():
        if p.is_dir() and (p.name=='Default' or p.name.startswith('Profile')):
            profiles.append(p)
    for prof in sorted(profiles):
        ck=prof/'Cookies'
        if not ck.exists():
            continue
        tmp=Path(tempfile.mkstemp(suffix='.sqlite')[1])
        try:
            shutil.copy2(ck,tmp)
            con=sqlite3.connect(tmp)
            cur=con.cursor()
            rows=cur.execute("select host_key, name, expires_utc from cookies where host_key like '%10jqka%' or host_key like '%thsi.cn%' or host_key like '%tzzb%'").fetchall()
            if rows:
                print('PROFILE', prof.name, 'cookie rows', len(rows))
                for r in rows[:20]:
                    print(' ', r)
            con.close()
        except Exception as e:
            print('PROFILE', prof.name, 'ERR', e)
        finally:
            try: tmp.unlink()
            except: pass
